// Read the classified JSON output and parse results
const fs = require('fs');
const outputPath = '/app/data/mentions_classified.json';

try {
  const raw = fs.readFileSync(outputPath, 'utf8');
  const classified = JSON.parse(raw);
  console.log(`Loaded ${classified.length} classified mentions`);
  return classified.map(m => ({ json: m }));
} catch (e) {
  console.error('Failed to read classified output:', e.message);
  return [{ json: { error: e.message } }];
}

// Alert detection — flag negative spikes and crisis mentions
const mentions = $input.all().map(i => i.json);
const alerts = [];
const brands = [...new Set(mentions.map(m => m.brand))];

for (const brand of brands) {
  const brandMentions = mentions.filter(m => m.brand === brand);
  const negative = brandMentions.filter(m => m.sentiment === 'negative');
  const crisis = brandMentions.filter(m => m.is_crisis === true || m.is_crisis === 'true');

  // Crisis alert
  if (crisis.length > 0) {
    alerts.push({
      type: 'crisis',
      brand,
      severity: 'critical',
      message: `${crisis.length} crisis-level mention(s) detected for ${brand}`,
      count: crisis.length
    });
  }

  // Negative spike (simple threshold for N8N — full baseline logic is in analytics.ts)
  if (negative.length >= 5) {
    alerts.push({
      type: 'negative_spike',
      brand,
      severity: negative.length >= 10 ? 'high' : 'medium',
      message: `Negative spike: ${negative.length} negative mentions for ${brand} in this batch`,
      count: negative.length
    });
  }
}

console.log(`Generated ${alerts.length} alert(s)`);
return alerts.length > 0
  ? alerts.map(a => ({ json: a }))
  : [{ json: { status: 'no_alerts' } }];

// Write final classified mentions to the data file read by the Next.js app
// In production: insert into PostgreSQL/MongoDB instead
const fs = require('fs');
const mentions = $input.all().map(i => i.json);
const outputPath = '/app/data/mentions_classified.json';

try {
  fs.writeFileSync(outputPath, JSON.stringify(mentions, null, 2), 'utf8');
  console.log(`Wrote ${mentions.length} mentions to ${outputPath}`);
  return [{ json: { status: 'success', count: mentions.length, path: outputPath } }];
} catch (e) {
  return [{ json: { status: 'error', message: e.message } }];
}
